import{_ as a,a as t}from"./chunks/webdav在win显示效果.BVTuSvY9.js";import{_ as i,o as l,c as s,a2 as d}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"WebDAV Site Access (Beta)","description":"","frontmatter":{},"headers":[],"relativePath":"ta/Safety/webdav-site-access.md","filePath":"ta/Safety/webdav-site-access.md","lastUpdated":1781962217000}'),n={name:"ta/Safety/webdav-site-access.md"};function o(r,e,c,p,h,g){return l(),s("div",null,[...e[0]||(e[0]=[d('<h1 id="webdav-site-access-beta" tabindex="-1">WebDAV Site Access (Beta) <a class="header-anchor" href="#webdav-site-access-beta" aria-label="Permalink to &quot;WebDAV Site Access (Beta)&quot;">​</a></h1><p>Security Settings-ல் உள்ள WebDAV setting உங்கள் ImgBed site-ஐ WebDAV endpoint ஆக வெளிப்படுத்தும்.</p><p>enable செய்த பிறகு Windows, macOS, mobile file managers, அல்லது WebDAV-compatible client மூலம் ImgBed files-ஐ remote folder போல browse, upload, delete, manage செய்யலாம்.</p><p>இது site-இன் WebDAV access entry. Upload Settings-ல் உள்ள WebDAV storage channel-இல் இருந்து வேறு. upload channel files-ஐ third-party WebDAV service-ல் store செய்கிறது. இந்த setting ImgBed site-ஐ clients-க்கு WebDAV access வழங்க செய்கிறது.</p><h2 id="எங்கு-configure-செய்வது" tabindex="-1">எங்கு Configure செய்வது <a class="header-anchor" href="#எங்கு-configure-செய்வது" aria-label="Permalink to &quot;எங்கு Configure செய்வது&quot;">​</a></h2><p>admin panel திறந்து செல்லவும்:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; WebDAV</span></span></code></pre></div><p>Available settings:</p><ul><li>Enable</li><li>Username</li><li>Password</li><li>Image loading mode</li><li>Default channel</li></ul><h2 id="இந்த-feature-என்ன-செய்கிறது" tabindex="-1">இந்த Feature என்ன செய்கிறது <a class="header-anchor" href="#இந்த-feature-என்ன-செய்கிறது" aria-label="Permalink to &quot;இந்த Feature என்ன செய்கிறது&quot;">​</a></h2><p>WebDAV enabled ஆன பிறகு ImgBed fixed access URL தரும்:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/dav</span></span></code></pre></div><p>ImgBed file directory-க்கு connect செய்ய இந்த URL பயன்படுத்தவும்.</p><p>சரியான use cases:</p><ul><li>computer file manager-ல் இருந்து ImgBed files நேரடியாக browse செய்ய.</li><li>images-ஐ WebDAV folder-க்கு drag செய்து upload செய்ய.</li><li>local file manager மூலம் ImgBed folders organize செய்ய.</li><li>WebDAV-compatible software மூலம் images sync/manage செய்ய.</li><li>admin panel திறக்காமல் ImgBed content access செய்ய.</li></ul><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><h3 id="enable" tabindex="-1">Enable <a class="header-anchor" href="#enable" aria-label="Permalink to &quot;Enable&quot;">​</a></h3><p>WebDAV endpoint-ஐ on செய்கிறது.</p><p>disabled என்றால் clients WebDAV மூலம் connect செய்ய முடியாது.</p><h3 id="username-மற்றும்-password" tabindex="-1">Username மற்றும் Password <a class="header-anchor" href="#username-மற்றும்-password" aria-label="Permalink to &quot;Username மற்றும் Password&quot;">​</a></h3><p>WebDAV clients connect செய்யும்போது இந்த credentials பயன்படுத்தப்படும்.</p><p>Dedicated WebDAV username/password பயன்படுத்தவும். admin password அல்லது upload password மீண்டும் பயன்படுத்த வேண்டாம்.</p><p>username அல்லது password காலியாக இருந்தால் WebDAV clients சரியாக connect செய்ய முடியாது.</p><h3 id="image-loading-mode" tabindex="-1">Image Loading Mode <a class="header-anchor" href="#image-loading-mode" aria-label="Permalink to &quot;Image Loading Mode&quot;">​</a></h3><p>WebDAV clients images படிக்கும் போது எந்த image URL-ஐ prefer செய்ய வேண்டும் என்பதை image loading mode தீர்மானிக்கும்.</p><p>Common choices:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Description</th></tr></thead><tbody><tr><td>Smart loading</td><td>ImgBed context அடிப்படையில் தேர்வு செய்யும். normal use-க்கு recommended.</td></tr><tr><td>Original</td><td>original images-ஐ prefer செய்யும்.</td></tr><tr><td>Thumbnail</td><td>thumbnails-ஐ prefer செய்யும். fast preview-க்கு useful.</td></tr></tbody></table><p>நிச்சயமில்லையெனில் <code>Smart loading</code> வைத்திருக்கவும்.</p><h3 id="default-channel" tabindex="-1">Default Channel <a class="header-anchor" href="#default-channel" aria-label="Permalink to &quot;Default Channel&quot;">​</a></h3><p>default channel WebDAV uploads-க்கு பயன்படுத்தப்படும்.</p><p>Windows அல்லது வேறு client மூலம் WebDAV directory-க்கு files copy செய்தால், ImgBed selected default upload channel வழியாக upload செய்யும்.</p><p>default channel selected இல்லையெனில் browsing வேலை செய்யலாம், ஆனால் uploads fail ஆகலாம்.</p><h2 id="windows-11-ல்-webdav-access" tabindex="-1">Windows 11-ல் WebDAV Access <a class="header-anchor" href="#windows-11-ல்-webdav-access" aria-label="Permalink to &quot;Windows 11-ல் WebDAV Access&quot;">​</a></h2><p>Windows 11 WebDAV-ஐ network location ஆக add செய்யலாம்.</p><ol><li><code>This PC</code> திறக்கவும்.</li><li><code>Add a network location</code> தேர்வு செய்யவும்.</li><li><code>https://your-domain.com/dav</code> உள்ளிடவும்.</li><li>prompt வந்தால் WebDAV username/password உள்ளிடவும்.</li><li>wizard முடிக்கவும். WebDAV directory File Explorer-ல் திறக்கப்படும்.</li></ol><p><img src="'+a+'" alt="Add WebDAV in Windows 11" loading="lazy"></p><p>add செய்த பிறகு WebDAV directory Windows File Explorer-ல் தெரியும். normal folder போல files open, copy, manage செய்யலாம்.</p><p><img src="'+t+'" alt="WebDAV in Windows" loading="lazy"></p><h2 id="supported-operations" tabindex="-1">Supported Operations <a class="header-anchor" href="#supported-operations" aria-label="Permalink to &quot;Supported Operations&quot;">​</a></h2><p>successful WebDAV connection பிறகு பொதுவாக:</p><ul><li>files மற்றும் folders பார்க்கலாம்.</li><li>files upload செய்யலாம்.</li><li>folders உருவாக்கலாம்.</li><li>files/folders rename செய்யலாம்.</li><li>files move செய்யலாம்.</li><li>files delete செய்யலாம்.</li></ul><p>WebDAV everyday access மற்றும் சிறிய அளவிலான file management-க்கு நல்லது. பெரிய moves, bulk deletes, complex organization-க்கு admin panel பயன்படுத்தவும்.</p><h2 id="login-device-management" tabindex="-1">Login Device Management <a class="header-anchor" href="#login-device-management" aria-label="Permalink to &quot;Login Device Management&quot;">​</a></h2><p>successful WebDAV connections Login Device Management-இன் WebDAV tab-ல் தோன்றும்.</p><p>அங்கே WebDAV clients review செய்து தேவையானபோது old devices force offline செய்யலாம்.</p><p>WebDAV username அல்லது password மாற்றினால் old clients மீண்டும் sign in செய்ய வேண்டும்.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="windows-மீண்டும்-மீண்டும்-username-password-கேட்கிறது" tabindex="-1">Windows மீண்டும் மீண்டும் Username/Password கேட்கிறது <a class="header-anchor" href="#windows-மீண்டும்-மீண்டும்-username-password-கேட்கிறது" aria-label="Permalink to &quot;Windows மீண்டும் மீண்டும் Username/Password கேட்கிறது&quot;">​</a></h3><p>சரிபார்க்கவும்:</p><ul><li>URL <code>https://your-domain.com/dav</code>.</li><li>username/password WebDAV settings-க்கு match ஆகிறது.</li><li>WebDAV enabled.</li><li>site HTTPS மூலம் access ஆகிறது.</li></ul><h3 id="browsing-வேலை-செய்கிறது-ஆனால்-uploading-fail-ஆகிறது" tabindex="-1">Browsing வேலை செய்கிறது, ஆனால் Uploading fail ஆகிறது <a class="header-anchor" href="#browsing-வேலை-செய்கிறது-ஆனால்-uploading-fail-ஆகிறது" aria-label="Permalink to &quot;Browsing வேலை செய்கிறது, ஆனால் Uploading fail ஆகிறது&quot;">​</a></h3><p><code>Default channel</code> பார்க்கவும்.</p><p>WebDAV uploads-க்கு default upload channel தேவை. அது missing, disabled, அல்லது misconfigured என்றால் uploads fail ஆகலாம்.</p><h3 id="access-speed-நிலையாக-இல்லை" tabindex="-1">Access Speed நிலையாக இல்லை <a class="header-anchor" href="#access-speed-நிலையாக-இல்லை" aria-label="Permalink to &quot;Access Speed நிலையாக இல்லை&quot;">​</a></h3><p>WebDAV performance client, network, file count, default upload channel ஆகியவற்றை சார்ந்தது.</p><p>ஒரு directory-ல் நிறைய files இருந்தால், அவற்றை folders-ல் organize செய்யவும்.</p><h2 id="security-recommendations" tabindex="-1">Security Recommendations <a class="header-anchor" href="#security-recommendations" aria-label="Permalink to &quot;Security Recommendations&quot;">​</a></h2><ul><li>WebDAV access-க்கு HTTPS பயன்படுத்தவும்.</li><li>strong password அமைக்கவும்.</li><li>WebDAV password-ஐ நம்ப முடியாதவர்களுடன் பகிர வேண்டாம்.</li><li>பயன்படுத்தவில்லை என்றால் WebDAV off செய்யவும்.</li><li>Login Device Management-ல் unused WebDAV devices அவ்வப்போது clean up செய்யவும்.</li></ul><h2 id="webdav-upload-file-size" tabindex="-1">WebDAV Upload File Size <a class="header-anchor" href="#webdav-upload-file-size" aria-label="Permalink to &quot;WebDAV Upload File Size&quot;">​</a></h2><p>WebDAV clients browser upload page-இன் large-file chunking flow பயன்படுத்தாது. கீழே உள்ள suggested limits-ஐ விட பெரிய files-க்கு web upload page பயன்படுத்தவும்.</p><table tabindex="0"><thead><tr><th>Default Upload Channel</th><th style="text-align:right;">Suggested Single-File Limit for WebDAV</th></tr></thead><tbody><tr><td>Telegram</td><td style="text-align:right;">20 MB</td></tr><tr><td>Discord</td><td style="text-align:right;">10 MB</td></tr><tr><td>Cloudflare R2</td><td style="text-align:right;">30 MB</td></tr><tr><td>S3</td><td style="text-align:right;">30 MB</td></tr><tr><td>GitHub Releases</td><td style="text-align:right;">64 MB</td></tr><tr><td>GitLab Packages</td><td style="text-align:right;">64 MB</td></tr><tr><td>Hugging Face</td><td style="text-align:right;">20 MB</td></tr><tr><td>OneDrive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Google Drive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Dropbox</td><td style="text-align:right;">30 MB</td></tr><tr><td>Yandex Disk</td><td style="text-align:right;">30 MB</td></tr><tr><td>pCloud</td><td style="text-align:right;">30 MB</td></tr><tr><td>WebDAV</td><td style="text-align:right;">64 MB</td></tr></tbody></table>',61)])])}const f=i(n,[["render",o]]);export{m as __pageData,f as default};
